   193	// ParseLogMetrics implements engine-specific log parsing for Copilot CLI.
   194	//
   195	// Parsing Strategy:
   196	// 1. First attempts to parse as JSONL session format (from ~/.copilot/session-state/*.jsonl)
   197	// 2. Falls back to debug log format if JSONL parsing fails or finds no entries
   198	//
   199	// Token Counting Behavior:
   200	// Copilot CLI makes multiple API calls during a workflow run (one per turn).
   201	// Each API call returns a response with usage statistics including token counts.
   202	// This function accumulates token counts from ALL API responses to get the total
   203	// token usage for the entire workflow run.
   204	//
   205	// Example: If a run has 3 turns with token counts [1000, 1500, 800],
   206	// the total token usage will be 3300 (sum of all turns).
   207	//
   208	// This matches the behavior of the JavaScript parser in parse_copilot_log.cjs.
   209	func (e *CopilotEngine) ParseLogMetrics(logContent string, verbose bool) LogMetrics {
   210		// Try parsing as JSONL session format first
   211		if metrics, success := e.parseSessionJSONL(logContent, verbose); success {
   212			copilotLogsLog.Printf("Successfully parsed session JSONL format")
   213			return metrics
   214		}
   215	
   216		// Fall back to debug log format parsing
   217		copilotLogsLog.Printf("JSONL parsing failed or no entries found, falling back to debug log format")
   218	
   219		var metrics LogMetrics
   220		var totalTokenUsage int
   221	
   222		lines := strings.Split(logContent, "\n")
   223		toolCallMap := make(map[string]*ToolCallInfo) // Track tool calls
   224		var currentSequence []string                  // Track tool sequence
   225		turns := 0
   226	
   227		// Track multi-line JSON blocks for token extraction
   228		var inDataBlock bool
   229		var currentJSONLines []string
   230	
   231		for _, line := range lines {
   232			// Skip empty lines
   233			if strings.TrimSpace(line) == "" {
   234				continue
   235			}
   236	
   237			// Detect start of a JSON data block from Copilot debug logs
   238			// Format: "YYYY-MM-DDTHH:MM:SS.sssZ [DEBUG] data:"
   239			if strings.Contains(line, "[DEBUG] data:") {
   240				inDataBlock = true
   241				currentJSONLines = []string{}
   242				// Each API response data block represents one LLM conversation turn.
   243				// Copilot CLI debug logs don't have "User:"/"Human:" patter<response clipped><NOTE>Due to the max output limit, only part of this file has been shown to you. You should retry this tool after you have searched inside the file with `grep -n` in order to find the line numbers of what you are looking for.</NOTE>mestamp := strings.Contains(line, "[DEBUG]")
   244	
   245				if hasTimestamp {
   246					// Strip the timestamp and [DEBUG] prefix to see what remains
   247					// Format: "YYYY-MM-DDTHH:MM:SS.sssZ [DEBUG] {json content}"
   248					_, after, ok := strings.Cut(line, "[DEBUG]")
   249					if ok {
   250						cleanLine := strings.TrimSpace(after) // Skip "[DEBUG]"
   251	
   252						// If after stripping, the line starts with JSON characters, it's part of JSON
   253						// Otherwise, it's a new log entry and we should end the block
   254						if strings.HasPrefix(cleanLine, "{") || strings.HasPrefix(cleanLine, "}") ||
   255							strings.HasPrefix(cleanLine, "[") || strings.HasPrefix(cleanLine, "]") ||
   256							strings.HasPrefix(cleanLine, "\"") {
   257							// This is JSON content - add it
   258							currentJSONLines = append(currentJSONLines, cleanLine)
   259						} else {
   260							// This is a new log line (not JSON content) - end of JSON block
   261							// Try to parse the accumulated JSON
   262							if len(currentJSONLines) > 0 {
   263								jsonStr := strings.Join(currentJSONLines, "\n")
   264								copilotLogsLog.Printf("Parsing JSON block with %d lines (%d bytes)", len(currentJSONLines), len(jsonStr))
   265								jsonMetrics := ExtractJSONMetrics(jsonStr, verbose)
   266								// Accumulate token usage from all responses (not just max)
   267								// This matches the JavaScript parser behavior in parse_copilot_log.cjs
   268								if jsonMetrics.TokenUsage > 0 {
   269									copilotLogsLog.Printf("Extracted %d tokens from JSON block", jsonMetrics.TokenUsage)
   270									totalTokenUsage += jsonMetrics.TokenUsage
   271								} else {
   272									copilotLogsLog.Printf("No tokens extracted from JSON block (possible format issue)")
   273								}
   274								if jsonMetrics.EstimatedCost > 0 {
   275									metrics.EstimatedCost += jsonMetrics.EstimatedCost
   276								}
   277	
   278								// Extract tool call sizes from the JSON response
   279								e.extractToolCallSizes(jsonStr, toolCallMap, verbose)
   280							}
   281	
   282							inDataBlock = false
   283							currentJSONLines = []string{}
   284						}
   285					}
   286				} else {
   287					// Line has no timestamp - it's raw JSON, add it
   288					currentJSONLines = append(currentJSONLines, line)
   289				}
   290			}
   291	
   292			// Extract tool calls and add to sequence and toolCallMap
   293			// "Executing tool: <name>" lines confirm tool execution and are used to populate
   294			// both the tool sequence and tool call statistics. This handles the common case where
   295			// Copilot CLI JSON blocks have empty tool_calls arrays but emit execution log lines.
   296			if toolName := e.parseCopilotToolCallsWithSequence(line, toolCallMap); toolName != "" {
   297				currentSequence = append(currentSequence, toolName)
   298			}
   299		}
