   301		// Process any remaining JSON block at the end of file
   302		if inDataBlock && len(currentJSONLines) > 0 {
   303			jsonStr := strings.Join(currentJSONLines, "\n")
   304			copilotLogsLog.Printf("Parsing final JSON block at EOF with %d lines (%d bytes)", len(currentJSONLines), len(jsonStr))
   305			jsonMetrics := ExtractJSONMetrics(jsonStr, verbose)
   306			// Accumulate token usage from all responses (not just max)
   307			if jsonMetrics.TokenUsage > 0 {
   308				copilotLogsLog.Printf("Extracted %d tokens from final JSON block", jsonMetrics.TokenUsage)
   309				totalTokenUsage += jsonMetrics.TokenUsage
   310			} else {
   311				copilotLogsLog.Printf("No tokens extracted from final JSON block (possible format issue)")
   312			}
   313			if jsonMetrics.EstimatedCost > 0 {
   314				metrics.EstimatedCost += jsonMetrics.EstimatedCost
   315			}
   316	
   317			// Extract tool call sizes from the JSON response
   318			e.extractToolCallSizes(jsonStr, toolCallMap, verbose)
   319		}
   320	
   321		// Finalize metrics using shared helper
   322		copilotLogsLog.Printf("Finalized metrics: totalTokenUsage=%d, turns=%d, toolCalls=%d", totalTokenUsage, turns, len(toolCallMap))
   323		FinalizeToolMetrics(FinalizeToolMetricsOptions{
   324			Metrics:         &metrics,
   325			ToolCallMap:     toolCallMap,
   326			CurrentSequence: currentSequence,
   327			Turns:           turns,
   328			TokenUsage:      totalTokenUsage,
   329		})
   330	
   331		return metrics
   332	}
