   406	// parseCopilotToolCallsWithSequence extracts tool call information from Copilot CLI log lines and returns tool name.
   407	// It also updates toolCallMap with the tool execution count for statistics tracking.
   408	func (e *CopilotEngine) parseCopilotToolCallsWithSequence(line string, toolCallMap map[string]*ToolCallInfo) string {
   409		// Look for "Executing tool:" pattern in Copilot logs
   410		if strings.Contains(line, "Executing tool:") {
   411			// Extract tool name from "Executing tool: <name>" format
   412			parts := strings.Split(line, "Executing tool:")
   413			if len(parts) > 1 {
   414				toolName := strings.TrimSpace(parts[1])
   415				if toolName == "" {
   416					return ""
   417				}
   418				// Update toolCallMap: this captures tool calls from execution log lines.
   419				// This is the primary source of tool call data in the Copilot CLI debug log
   420				// format, since JSON response blocks often have empty tool_calls arrays.
   421				if toolInfo, exists := toolCallMap[toolName]; exists {
   422					toolInfo.CallCount++
   423				} else {
   424					toolCallMap[toolName] = &ToolCallInfo{
   425						Name:      toolName,
   426						CallCount: 1,
   427					}
   428				}
   429				return toolName
   430			}
   431		}
   432	
   433		return ""
   434	}
