    33	// ExtractJSONMetrics extracts metrics from streaming JSON log lines
    34	func ExtractJSONMetrics(line string, verbose bool) LogMetrics {
    35		var metrics LogMetrics
    36	
    37		// Trim the line first
    38		trimmed := strings.TrimSpace(line)
    39		if trimmed == "" {
    40			return metrics
    41		}
    42	
    43		metricsLog.Printf("Extracting metrics from JSON line: line_length=%d", len(trimmed))
    44	
    45		// If the line isn't a clean JSON object, try to extract a JSON object substring
    46		jsonStr := trimmed
    47		if !strings.HasPrefix(trimmed, "{") || !strings.HasSuffix(trimmed, "}") {
    48			// Find first '{' and last '}' and attempt to parse that slice
    49			open := strings.Index(trimmed, "{")
    50			close := strings.LastIndex(trimmed, "}")
    51			if open == -1 || close == -1 || close <= open {
    52				return metrics
    53			}
    54			jsonStr = trimmed[open : close+1]
    55		}
    56	
    57		// Try to parse as generic JSON
    58		var jsonData map[string]any
    59		if err := json.Unmarshal([]byte(jsonStr), &jsonData); err != nil {
    60			// If parsing fails, try a relaxed approach: sometimes logs contain a JSON-like object with single quotes
    61			// Replace single quotes with double quotes as a last resort (not ideal, but helpful for noisy logs)
    62			relaxed := strings.ReplaceAll(jsonStr, "'", "\"")
    63			if err2 := json.Unmarshal([]byte(relaxed), &jsonData); err2 != nil {
