// tool name. It rejects common English stop words that are frequently false-positive
// extractions from natural language prose in agent logs.
func isPlausibleToolName(name string) bool {
	if name == "" {
		return false
	}
	// Reject common English stop words (case-insensitive)
	if commonEnglishStopWords[strings.ToLower(name)] {
		return false
	}
	return true
}

