func isPlausibleToolName(name string) bool {
	if name == "" {
		return false
	}
	if commonEnglishStopWords[strings.ToLower(name)] {
		return false
	}
	return true
}

func extractToolName(line string) string {
	for _, pattern := range toolNamePatterns {
		if matches := pattern.FindStringSubmatch(line); len(matches) > 1 {
			name := strings.TrimSpace(matches[1])
			if isPlausibleToolName(name) {
				return name
			}
			return ""
		}
	}
	return ""
}

func simulateParse(logContent string) map[string]int {
	toolCallMap := make(map[string]int)
	lines := strings.Split(logContent, "\n")
	for _, line := range lines {
		if strings.TrimSpace(line) == "" {
			continue
		}
		if matches := agentToolCallPattern.FindStringSubmatch(line); len(matches) > 1 {
			toolName := extractToolName(line)
			if toolName != "" {
				toolCallMap[toolName]++
			}
		}
	}
	return toolCallMap
}

